  Calendar, MapPin, Trash2, Plus, Gavel, Edit, 
  CalendarPlus, Clock, Share2, Printer, ArrowRightCircle,
  X, Loader2, FileText, Search, Filter, Layers, Layout
} from 'lucide-react';

const KUWAIT_COURTS = [
  "قصر العدل (مدينة الكويت)",
  "محكمة الاستئناف",
  "محكمة التمييز",
  "المحكمة الدستورية",
